import { describe, it, expect, vi, afterEach } from 'vitest';
import { ref, nextTick, defineComponent } from 'vue';
import { mount } from '@vue/test-utils';
import { announce, useFocusTrap, useArrowKeyNavigation, useSkipLink, useModalFocus } from '@/composables/useAccessibility';

describe('useAccessibility composables', () => {
  afterEach(() => {
    document.body.innerHTML = '';
    vi.clearAllMocks();
  });

  describe('announce', () => {
    it('should create and update announcer element', () => {
      // Use requestAnimationFrame mock
      vi.stubGlobal('requestAnimationFrame', (cb: FrameRequestCallback) => cb(0));
      
      announce('Hello World');
      const announcer = document.getElementById('a11y-announcer');
      expect(announcer).not.toBeNull();
      expect(announcer?.textContent).toBe('Hello World');
      expect(announcer?.getAttribute('aria-live')).toBe('polite');

      announce('Alert!', 'assertive');
      expect(announcer?.textContent).toBe('Alert!');
      expect(announcer?.getAttribute('aria-live')).toBe('assertive');
      
      vi.unstubAllGlobals();
    });
  });

  describe('useFocusTrap', () => {
    it('should trap focus within container', async () => {
      const container = document.createElement('div');
      container.innerHTML = `
        <button id="b1">First</button>
        <button id="b2">Second</button>
      `;
      document.body.appendChild(container);
      
      const b1 = document.getElementById('b1') as HTMLButtonElement;
      const b2 = document.getElementById('b2') as HTMLButtonElement;
      
      // In JSDOM offsetParent is always null unless we mock it
      Object.defineProperty(b1, 'offsetParent', { get: () => document.body });
      Object.defineProperty(b2, 'offsetParent', { get: () => document.body });

      const containerRef = { value: container };
      const { activate, deactivate } = useFocusTrap(containerRef);
      
      activate();
      await nextTick();
      
      // Focus should start at first element
      expect(document.activeElement).toBe(b1);
      
      // Tab from last to first
      b2.focus();
      const tabEvent = new KeyboardEvent('keydown', { key: 'Tab' });
      document.dispatchEvent(tabEvent);
      expect(document.activeElement).toBe(b1);
      
      // Shift+Tab from first to last
      const shiftTabEvent = new KeyboardEvent('keydown', { key: 'Tab', shiftKey: true });
      document.dispatchEvent(shiftTabEvent);
      expect(document.activeElement).toBe(b2);
      
      deactivate();
      document.body.removeChild(container);
    });
  });

  describe('useArrowKeyNavigation', () => {
    it('should navigate items with arrow keys', async () => {
        const item1 = document.createElement('button');
        const item2 = document.createElement('button');
        const container = document.createElement('div');
        container.appendChild(item1);
        container.appendChild(item2);
        document.body.appendChild(container);
        
        // JSDOM mock for visibility
        Object.defineProperty(item1, 'offsetParent', { get: () => document.body });
        Object.defineProperty(item2, 'offsetParent', { get: () => document.body });

        const items = ref([item1, item2]);
        const { handleKeyDown } = useArrowKeyNavigation(items);
        
        item1.focus();
        console.log('Active after focus:', (document.activeElement as any).tagName, (document.activeElement as any).id);
        expect(document.activeElement).toBe(item1);
        
        const event = new KeyboardEvent('keydown', { key: 'ArrowDown' });
        handleKeyDown(event);
        console.log('Active after handleKeyDown:', (document.activeElement as any).tagName, (document.activeElement as any).id);
        expect(document.activeElement).toBe(item2);
        
        const eventUp = new KeyboardEvent('keydown', { key: 'ArrowUp' });
        handleKeyDown(eventUp);
        expect(document.activeElement).toBe(item1);

        document.body.removeChild(container);
    });

    it('should loop around when loop is true', () => {
      const item1 = document.createElement('button');
      const item2 = document.createElement('button');
      document.body.appendChild(item1);
      document.body.appendChild(item2);
      Object.defineProperty(item1, 'offsetParent', { get: () => document.body });
      Object.defineProperty(item2, 'offsetParent', { get: () => document.body });
      const items = ref([item1, item2]);
      const { handleKeyDown } = useArrowKeyNavigation(items, { loop: true });
      
      item2.focus();
      const event = new KeyboardEvent('keydown', { key: 'ArrowDown' });
      handleKeyDown(event);
      expect(document.activeElement).toBe(item1);
    });

    it('should not loop around when loop is false', () => {
      const item1 = document.createElement('button');
      const item2 = document.createElement('button');
      document.body.appendChild(item1);
      document.body.appendChild(item2);
      Object.defineProperty(item1, 'offsetParent', { get: () => document.body });
      Object.defineProperty(item2, 'offsetParent', { get: () => document.body });
      const items = ref([item1, item2]);
      const { handleKeyDown } = useArrowKeyNavigation(items, { loop: false });
      
      item2.focus();
      const event = new KeyboardEvent('keydown', { key: 'ArrowDown' });
      handleKeyDown(event);
      expect(document.activeElement).toBe(item2);
    });

    it('should respect orientation', () => {
      const item1 = document.createElement('button');
      const item2 = document.createElement('button');
      document.body.appendChild(item1);
      document.body.appendChild(item2);
      Object.defineProperty(item1, 'offsetParent', { get: () => document.body });
      Object.defineProperty(item2, 'offsetParent', { get: () => document.body });
      const items = ref([item1, item2]);
      const { handleKeyDown } = useArrowKeyNavigation(items, { orientation: 'vertical' });
      
      item1.focus();
      const event = new KeyboardEvent('keydown', { key: 'ArrowRight' });
      handleKeyDown(event);
      expect(document.activeElement).toBe(item1); 
    });

    it('should handle Home and End keys', () => {
      const item1 = document.createElement('button');
      const item2 = document.createElement('button');
      const item3 = document.createElement('button');
      document.body.appendChild(item1);
      document.body.appendChild(item2);
      document.body.appendChild(item3);
      Object.defineProperty(item1, 'offsetParent', { get: () => document.body });
      Object.defineProperty(item2, 'offsetParent', { get: () => document.body });
      Object.defineProperty(item3, 'offsetParent', { get: () => document.body });
      const items = ref([item1, item2, item3]);
      const { handleKeyDown } = useArrowKeyNavigation(items);
      
      item2.focus();
      handleKeyDown(new KeyboardEvent('keydown', { key: 'Home' }));
      expect(document.activeElement).toBe(item1);

      handleKeyDown(new KeyboardEvent('keydown', { key: 'End' }));
      expect(document.activeElement).toBe(item3);
    });
  });

  describe('useSkipLink', () => {
    it('should focus target element', () => {
        const target = document.createElement('div');
        target.id = 'main-content';
        target.tabIndex = -1;
        document.body.appendChild(target);
        target.scrollIntoView = vi.fn();
        
        const { skipToContent } = useSkipLink('main-content');
        skipToContent();
        
        expect(document.activeElement).toBe(target);
        expect(target.scrollIntoView).toHaveBeenCalled();
        
        document.body.removeChild(target);
    });
  });

  describe('useModalFocus', () => {
    it('should activate and deactivate focus trap', async () => {
      const container = document.createElement('div');
      container.innerHTML = '<button id="m1">Modal Btn</button>';
      document.body.appendChild(container);
      
      const isOpen = ref(false);
      const modalRef = ref(container);
      
      const TestComponent = defineComponent({
        setup() {
          return useModalFocus(isOpen, modalRef);
        },
        template: '<div></div>'
      });
      
      const wrapper = mount(TestComponent);
      const { activateFocusTrap, deactivateFocusTrap } = wrapper.vm as any;
      
      const btn = document.getElementById('m1');
      if (btn) Object.defineProperty(btn, 'offsetParent', { get: () => document.body });

      activateFocusTrap();
      await nextTick();
      
      expect(document.activeElement).toBe(btn);
      
      deactivateFocusTrap();
      document.body.removeChild(container);
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { useAuthForm } from '@/composables/useAuthForm';
import { useAuthStore } from '@/store/authStore';
import { AuthService } from '@/services/authService';
import { showSuccess, showError } from '@/store/toast';
import { useRouter } from 'vue-router';
import { setActivePinia, createPinia } from 'pinia';
import { defineComponent } from 'vue';
import { mount } from '@vue/test-utils';

// Mock dependencies
vi.mock('@/services/authService');
vi.mock('@/store/toast');
vi.mock('vue-router', () => ({
  useRouter: vi.fn(),
}));
vi.mock('@/utils/env', () => ({
  getEnvVar: vi.fn((_key) => 'mock-env-value'),
  isDev: vi.fn(() => true),
}));
vi.mock('@/utils/oauth', () => ({
  getGoogleAuthUrl: vi.fn().mockResolvedValue({ url: 'http://google.com/auth', codeVerifier: 'xyz' }),
}));

describe('useAuthForm', () => {
  let mockRouter: { push: ReturnType<typeof vi.fn> };

  beforeEach(() => {
    setActivePinia(createPinia());
    mockRouter = { push: vi.fn() };
    (useRouter as unknown as ReturnType<typeof vi.fn>).mockReturnValue(mockRouter);
    
    // Mock localStorage
    const storageMock = (() => {
      let store: Record<string, string> = {};
      return {
        getItem: vi.fn((key: string) => store[key] || null),
        setItem: vi.fn((key: string, value: string) => {
          store[key] = value.toString();
        }),
        removeItem: vi.fn((key: string) => {
          delete store[key];
        }),
        clear: vi.fn(() => {
          store = {};
        }),
        key: vi.fn(),
        length: 0,
      };
    })();

    Object.defineProperty(globalThis, 'localStorage', {
      value: storageMock,
      writable: true,
      configurable: true,
    });

    vi.clearAllMocks();
  });

  const createTestComponent = (initialMode: 'login' | 'register' = 'login') => defineComponent({
    setup() {
      return useAuthForm(initialMode);
    },
    render() {
      return null;
    },
  });

  describe('Initial State', () => {
    it('should initialize correctly for login mode', () => {
      const wrapper = mount(createTestComponent('login'));
      const vm = wrapper.vm;

      expect(vm.isLogin).toBe(true);
      expect(vm.form).toEqual({ email: '', password: '', name: '' });
      expect(vm.isLoading).toBe(false);
    });

    it('should initialize correctly for register mode', () => {
      const wrapper = mount(createTestComponent('register'));
      const vm = wrapper.vm;

      expect(vm.isLogin).toBe(false);
    });
  });

  describe('Validation', () => {
    it('should validate required fields', async () => {
      const wrapper = mount(createTestComponent('login'));
      const vm = wrapper.vm as any;
      
      await vm.handleSubmit();
      expect(vm.formErrors.email).toBe('Email is required');
      expect(vm.formErrors.password).toBe('Password is required');
      expect(AuthService.login).not.toHaveBeenCalled();
    });

    it('should validate password length for registration', async () => {
      const wrapper = mount(createTestComponent('register'));
      const vm = wrapper.vm as any;
      
      vm.form.name = 'Test User';
      vm.form.email = 'test@example.com';
      vm.form.password = 'short';
      
      await vm.handleSubmit();
      expect(vm.formErrors.password).toBe('Password must be at least 8 characters');
    });
  });

  describe('Submit Logic', () => {
    it('should handle successful login', async () => {
      const wrapper = mount(createTestComponent('login'));
      const vm = wrapper.vm;

      vm.form.email = 'test@example.com';
      vm.form.password = 'password123';
      
      const mockAuthData = { 
        user: { name: 'Test User' }, 
        access_token: 'token' 
      };
      (AuthService.login as unknown as ReturnType<typeof vi.fn>).mockResolvedValue(mockAuthData);

      await vm.handleSubmit();

      expect(useAuthStore().user).toEqual(mockAuthData.user);
      expect(showSuccess).toHaveBeenCalled();
      expect(mockRouter.push).toHaveBeenCalledWith('/upload');
    });

    it('should handle successful registration', async () => {
      const wrapper = mount(createTestComponent('register'));
      const vm = wrapper.vm;

      vm.form.name = 'New User';
      vm.form.email = 'new@example.com';
      vm.form.password = 'password123';
      
      const mockAuthData = { 
        user: { name: 'New User' }, 
        access_token: 'token' 
      };
      (AuthService.signup as unknown as ReturnType<typeof vi.fn>).mockResolvedValue(mockAuthData);

      await vm.handleSubmit();

      expect(useAuthStore().user).toEqual(mockAuthData.user);
      expect(showSuccess).toHaveBeenCalled();
      expect(mockRouter.push).toHaveBeenCalledWith('/upload');
    });

    it('should handle API errors', async () => {
      const wrapper = mount(createTestComponent('login'));
      const vm = wrapper.vm;

      vm.form.email = 'test@example.com';
      vm.form.password = 'password123';
      
      (AuthService.login as unknown as ReturnType<typeof vi.fn>).mockRejectedValue(new Error('Invalid credentials'));

      await vm.handleSubmit();

      expect(showError).toHaveBeenCalledWith('Invalid credentials', 'Authentication Failed');
      expect(vm.isLoading).toBe(false);
    });
  });

  describe('Google Login', () => {
    it('should initiate Google login', async () => {
      // Mock window.location.href
      const originalLocation = window.location;
      delete (window as any).location;
      window.location = { href: '', origin: 'http://localhost:3000' } as any;

      const wrapper = mount(createTestComponent('login'));
      const vm = wrapper.vm;

      await vm.handleGoogleLogin();

      expect(window.location.href).toBe('http://google.com/auth'); // from mock
      
      // Restore
      window.location = originalLocation;
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { useGeolocation } from '@/composables/useGeolocation';
import { flushPromises, mount } from '@vue/test-utils';
import { defineComponent } from 'vue';

// Create a wrapper component for testing lifecycle hooks
const createTestComponent = () =>
  defineComponent({
    setup() {
      return useGeolocation();
    },
    render() {
      return null;
    },
  });

describe('useGeolocation', () => {
  let mockGeolocation: {
    getCurrentPosition: ReturnType<typeof vi.fn>;
    watchPosition: ReturnType<typeof vi.fn>;
    clearWatch: ReturnType<typeof vi.fn>;
  };
  let originalGeolocation: Geolocation;

  beforeEach(() => {
    // Mock navigator.geolocation
    mockGeolocation = {
      getCurrentPosition: vi.fn(),
      watchPosition: vi.fn().mockReturnValue(123), // returns watchId
      clearWatch: vi.fn(),
    };
    originalGeolocation = navigator.geolocation;
    Object.defineProperty(navigator, 'geolocation', {
      value: mockGeolocation,
      writable: true,
      configurable: true,
    });

    // Mock fetch for IP fallback
    globalThis.fetch = vi.fn();
    vi.clearAllMocks();
  });

  afterEach(() => {
    Object.defineProperty(navigator, 'geolocation', {
      value: originalGeolocation,
      writable: true,
      configurable: true,
    });
  });

  describe('Initial State', () => {
    it('should initialize with default state', () => {
      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      expect(vm.userLocation).toBeNull();
      expect(vm.error).toBeNull();
      expect(vm.isLoading).toBe(false);
      expect(vm.permissionDenied).toBe(false);

      wrapper.unmount();
    });
  });

  describe('getCurrentPosition', () => {
    it('should get current position successfully', async () => {
      const mockPosition: GeolocationPosition = {
        coords: {
          latitude: 13.7563,
          longitude: 100.5018,
          accuracy: 10,
          altitude: null,
          altitudeAccuracy: null,
          heading: null,
          speed: null,
        },
        timestamp: Date.now(),
      };

      mockGeolocation.getCurrentPosition.mockImplementation(
        (successCallback: PositionCallback) => {
          successCallback(mockPosition);
        }
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      const result = await vm.getCurrentPosition();

      expect(result).toEqual({ lat: 13.7563, lng: 100.5018 });
      expect(vm.userLocation).toEqual({ lat: 13.7563, lng: 100.5018 });
      expect(vm.isLoading).toBe(false);
      expect(vm.permissionDenied).toBe(false);

      wrapper.unmount();
    });

    it('should handle permission denied and fallback to IP', async () => {
      const ipLocation = { latitude: '14.0', longitude: '101.0' };

      mockGeolocation.getCurrentPosition.mockImplementation(
        (_success: PositionCallback, errorCallback: PositionErrorCallback) => {
          errorCallback({
            code: 1,
            message: 'User denied geolocation permission',
            PERMISSION_DENIED: 1,
            POSITION_UNAVAILABLE: 2,
            TIMEOUT: 3,
          });
        }
      );

      (globalThis.fetch as ReturnType<typeof vi.fn>).mockResolvedValue({
        json: () => Promise.resolve(ipLocation),
      });

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      const result = await vm.getCurrentPosition();

      expect(vm.permissionDenied).toBe(true);
      expect(result).toEqual({ lat: 14.0, lng: 101.0 });

      wrapper.unmount();
    });

    it('should set error when both geolocation and IP fallback fail', async () => {
      mockGeolocation.getCurrentPosition.mockImplementation(
        (_success: PositionCallback, errorCallback: PositionErrorCallback) => {
          errorCallback({
            code: 2,
            message: 'Position unavailable',
            PERMISSION_DENIED: 1,
            POSITION_UNAVAILABLE: 2,
            TIMEOUT: 3,
          });
        }
      );

      (globalThis.fetch as ReturnType<typeof vi.fn>).mockRejectedValue(
        new Error('Network error')
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      const result = await vm.getCurrentPosition();

      expect(result).toBeNull();
      expect(vm.error).toBe('Position unavailable');
      expect(vm.isLoading).toBe(false);

      wrapper.unmount();
    });

    it('should handle missing geolocation API', async () => {
      Object.defineProperty(navigator, 'geolocation', {
        value: undefined,
        writable: true,
        configurable: true,
      });

      (globalThis.fetch as ReturnType<typeof vi.fn>).mockRejectedValue(
        new Error('Network error')
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      const result = await vm.getCurrentPosition();

      expect(result).toBeNull();
      expect(vm.error).toBe('Geolocation is not supported by this browser');

      wrapper.unmount();
    });
  });

  describe('watchPosition', () => {
    it('should start watching position', async () => {
      const mockPosition: GeolocationPosition = {
        coords: {
          latitude: 13.7563,
          longitude: 100.5018,
          accuracy: 10,
          altitude: null,
          altitudeAccuracy: null,
          heading: null,
          speed: null,
        },
        timestamp: Date.now(),
      };

      mockGeolocation.getCurrentPosition.mockImplementation(
        (successCallback: PositionCallback) => {
          successCallback(mockPosition);
        }
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      await vm.startWatchingPosition();

      expect(mockGeolocation.watchPosition).toHaveBeenCalled();

      wrapper.unmount();
    });

    it('should skip watching if permission denied', async () => {
      // Mock getCurrentPosition to set permissionDenied
      mockGeolocation.getCurrentPosition.mockImplementation(
        (_success: PositionCallback, errorCallback: PositionErrorCallback) => {
          errorCallback({
            code: 1,
            message: 'User denied geolocation permission',
            PERMISSION_DENIED: 1,
            POSITION_UNAVAILABLE: 2,
            TIMEOUT: 3,
          });
        }
      );

      (globalThis.fetch as ReturnType<typeof vi.fn>).mockRejectedValue(
        new Error('Network error')
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      // First call sets permissionDenied
      await vm.getCurrentPosition();
      expect(vm.permissionDenied).toBe(true);

      // Now try to watch - should be skipped
      mockGeolocation.watchPosition.mockClear();
      await vm.startWatchingPosition();

      expect(mockGeolocation.watchPosition).not.toHaveBeenCalled();

      wrapper.unmount();
    });

    it('should stop watching position', async () => {
      const mockPosition: GeolocationPosition = {
        coords: {
          latitude: 13.7563,
          longitude: 100.5018,
          accuracy: 10,
          altitude: null,
          altitudeAccuracy: null,
          heading: null,
          speed: null,
        },
        timestamp: Date.now(),
      };

      mockGeolocation.getCurrentPosition.mockImplementation(
        (successCallback: PositionCallback) => {
          successCallback(mockPosition);
        }
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      await vm.startWatchingPosition();
      vm.stopWatchingPosition();

      expect(mockGeolocation.clearWatch).toHaveBeenCalledWith(123);

      wrapper.unmount();
    });
  });

  describe('cleanup', () => {
    it('should clean up on unmount', async () => {
      const mockPosition: GeolocationPosition = {
        coords: {
          latitude: 13.7563,
          longitude: 100.5018,
          accuracy: 10,
          altitude: null,
          altitudeAccuracy: null,
          heading: null,
          speed: null,
        },
        timestamp: Date.now(),
      };

      mockGeolocation.getCurrentPosition.mockImplementation(
        (successCallback: PositionCallback) => {
          successCallback(mockPosition);
        }
      );

      const wrapper = mount(createTestComponent());
      const vm = wrapper.vm as ReturnType<typeof useGeolocation>;

      await vm.startWatchingPosition();
      await flushPromises();

      wrapper.unmount();

      expect(mockGeolocation.clearWatch).toHaveBeenCalledWith(123);
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { useImageLoader } from '@/composables/useImageLoader';
import { mount, flushPromises } from '@vue/test-utils';
import { defineComponent, nextTick } from 'vue';

describe('useImageLoader', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
    vi.restoreAllMocks();
  });

  describe('Initial State', () => {
    it('should initialize with correct state for non-lazy loading', () => {
      const TestComponent = defineComponent({
        setup() {
          const result = useImageLoader({ src: 'https://example.com/cat.jpg', lazy: false });
          return result;
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;

      expect(vm.isLoaded).toBe(false);
      expect(vm.hasError).toBe(false);
      expect(vm.isIntersecting).toBe(true); // lazy=false means immediate intersection
      expect(vm.imageRef).toBeNull();

      wrapper.unmount();
    });

    it('should be intersecting immediately when lazy is false', () => {
      const TestComponent = defineComponent({
        setup() {
          return useImageLoader({ src: 'https://example.com/cat.jpg', lazy: false });
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;

      expect(vm.isIntersecting).toBe(true);

      wrapper.unmount();
    });
  });

  describe('Load Handling', () => {
    it('should set isLoaded to true on handleLoad', () => {
      const TestComponent = defineComponent({
        setup() {
          return useImageLoader({ src: 'https://example.com/cat.jpg', lazy: false });
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;

      expect(vm.isLoaded).toBe(false);
      vm.handleLoad();
      expect(vm.isLoaded).toBe(true);

      wrapper.unmount();
    });
  });

  describe('Error Handling', () => {
    it('should set hasError to true on handleError', () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      const TestComponent = defineComponent({
        setup() {
          return useImageLoader({ src: 'https://example.com/cat.jpg', lazy: false });
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as any;

      expect(vm.hasError).toBe(false);
      vm.handleError(new Event('error'));
      expect(vm.hasError).toBe(true);
      expect(consoleSpy).toHaveBeenCalled();

      wrapper.unmount();
      consoleSpy.mockRestore();
    });
  });

  describe('Retry', () => {
    it('should reset state on retry', async () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      const TestComponent = defineComponent({
        setup() {
          return useImageLoader({ src: 'https://example.com/cat.jpg', lazy: false });
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;

      // Simulate error
      vm.handleError(new Event('error'));
      expect(vm.hasError).toBe(true);

      // Retry (for non-lazy, it just resets state)
      vm.retry();
      expect(vm.hasError).toBe(false);
      expect(vm.isLoaded).toBe(false);

      wrapper.unmount();
      consoleSpy.mockRestore();
    });

    it('should reset intersection for lazy loading on retry', async () => {
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

      // Skip IntersectionObserver for this test
      const originalIO = globalThis.IntersectionObserver;
      // @ts-expect-error - removing for test
      delete globalThis.IntersectionObserver;

      const TestComponent = defineComponent({
        setup() {
          return useImageLoader({ src: 'https://example.com/cat.jpg', lazy: true });
        },
        render() {
          return null;
        },
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;

      // Simulate error
      vm.handleError(new Event('error'));
      expect(vm.hasError).toBe(true);

      // Retry
      vm.retry();
      expect(vm.hasError).toBe(false);
      expect(vm.isLoaded).toBe(false);
      expect(vm.isIntersecting).toBe(false);

      // After timeout, should re-intersect
      vi.advanceTimersByTime(100);
      await nextTick();
      expect(vm.isIntersecting).toBe(true);

      wrapper.unmount();
      consoleSpy.mockRestore();

      // Restore
      globalThis.IntersectionObserver = originalIO;
    });
  });

  describe('Fallback for no IntersectionObserver', () => {
    it('should set isIntersecting true if no IntersectionObserver', async () => {
      // Remove IntersectionObserver
      const originalIO = globalThis.IntersectionObserver;
      // @ts-expect-error - Removing for test
      delete globalThis.IntersectionObserver;

      const TestComponent = defineComponent({
        setup() {
          const loader = useImageLoader({
            src: 'https://example.com/cat.jpg',
            lazy: true,
          });
          return loader;
        },
        template: '<div ref="imageRef">Image</div>',
      });

      const wrapper = mount(TestComponent);
      const vm = wrapper.vm as ReturnType<typeof useImageLoader>;
      await flushPromises();

      expect(vm.isIntersecting).toBe(true);

      wrapper.unmount();

      // Restore
      globalThis.IntersectionObserver = originalIO;
    });
  });
});

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { logMetric, measureAsync, measureSync, useRenderTime, useApiTiming, getMetrics, clearMetrics, getPerformanceSummary, useWebVitals } from '@/composables/usePerformance';
import { mount } from '@vue/test-utils';
import { defineComponent, nextTick } from 'vue';

describe('usePerformance', () => {
  let originalImportMeta: any;

  beforeEach(() => {
    vi.useFakeTimers();
    clearMetrics();
    
    originalImportMeta = { ...import.meta };
    
    // Mock import.meta.env
    vi.stubGlobal('import.meta', {
      env: { DEV: true, PROD: false }
    });
    
    // Mock Performance APIs
    globalThis.performance = {
      now: vi.fn(),
      getEntriesByType: vi.fn(() => []),
      getEntriesByName: vi.fn(() => []),
    } as any;
    
    // Mock PerformanceObserver to handle multiple observers
    const callbacks = new Map<string, any>();
    globalThis.PerformanceObserver = vi.fn().mockImplementation(function(cb) {
      return {
        observe: vi.fn().mockImplementation((options) => {
          if (options.type) {
            callbacks.set(options.type, cb);
          }
        }),
        disconnect: vi.fn()
      };
    }) as any;

    (globalThis as any).triggerPerformanceObserver = (type: string, entries: any[]) => {
      const cb = callbacks.get(type);
      if (cb) {
        cb({
          getEntries: () => entries
        });
      }
    };

    // Setup now() sequence via mock implementation if needed
    (globalThis.performance.now as any).mockReturnValue(1000);
  });

  afterEach(() => {
    vi.restoreAllMocks();
    vi.stubGlobal('import.meta', originalImportMeta);
  });

  describe('logMetric', () => {
    it('should add metric to store', () => {
      logMetric({
        name: 'test-metric',
        value: 123,
        unit: 'ms',
        timestamp: Date.now(),
      });
      
      const metrics = getMetrics();
      expect(metrics).toHaveLength(1);
      expect(metrics[0].name).toBe('test-metric');
      expect(metrics[0].value).toBe(123);
    });

    it('should handle multiple metrics', () => {
      logMetric({ name: 'metric1', value: 100, unit: 'ms', timestamp: 1 });
      logMetric({ name: 'metric2', value: 200, unit: 'ms', timestamp: 2 });
      logMetric({ name: 'metric1', value: 150, unit: 'ms', timestamp: 3 });

      expect(getMetrics()).toHaveLength(3);
    });
  });

  describe('clearMetrics', () => {
    it('should clear all metrics', () => {
      logMetric({ name: 'test', value: 1, unit: 'ms', timestamp: 1 });
      expect(getMetrics()).toHaveLength(1);
      
      clearMetrics();
      expect(getMetrics()).toHaveLength(0);
    });
  });

  describe('getPerformanceSummary', () => {
    it('should return empty object when no metrics', () => {
      expect(getPerformanceSummary()).toEqual({});
    });

    it('should calculate summary statistics', () => {
      logMetric({ name: 'api', value: 100, unit: 'ms', timestamp: 1 });
      logMetric({ name: 'api', value: 200, unit: 'ms', timestamp: 2 });
      logMetric({ name: 'api', value: 300, unit: 'ms', timestamp: 3 });

      const summary = getPerformanceSummary();
      expect(summary.api).toBeDefined();
      expect(summary.api.count).toBe(3);
      expect(summary.api.min).toBe(100);
      expect(summary.api.max).toBe(300);
      expect(summary.api.avg).toBe(200);
    });

    it('should handle multiple metric types', () => {
      logMetric({ name: 'render', value: 50, unit: 'ms', timestamp: 1 });
      logMetric({ name: 'api', value: 100, unit: 'ms', timestamp: 2 });

      const summary = getPerformanceSummary();
      expect(summary.render).toBeDefined();
      expect(summary.api).toBeDefined();
    });
  });

  describe('measureAsync', () => {
    it('should measure execution time', async () => {
      (globalThis.performance.now as any)
        .mockReturnValueOnce(1000) // start
        .mockReturnValueOnce(1500); // end
        
      const fn = vi.fn().mockResolvedValue('result');
      
      const result = await measureAsync('test-async', fn);
      
      expect(result).toBe('result');
      expect(fn).toHaveBeenCalled();
      
      const metrics = getMetrics();
      expect(metrics).toHaveLength(1);
      expect(metrics[0].name).toBe('test-async');
      expect(metrics[0].value).toBe(500);
    });

    it('should measure time even if function throws', async () => {
       (globalThis.performance.now as any)
        .mockReturnValueOnce(1000) // start
        .mockReturnValueOnce(1200); // end (in catch)

      const fn = vi.fn().mockRejectedValue(new Error('fail'));
      
      await expect(measureAsync('test-fail', fn)).rejects.toThrow('fail');
      
      const metrics = getMetrics();
      expect(metrics).toHaveLength(1);
      expect(metrics[0].name).toBe('test-fail');
      expect(metrics[0].value).toBe(200);
      expect(metrics[0].metadata?.success).toBe(false);
    });

    it('should pass metadata to logged metric', async () => {
      (globalThis.performance.now as any)
        .mockReturnValueOnce(1000)
        .mockReturnValueOnce(1100);

      await measureAsync('test', async () => 'ok', { extra: 'data' });

      const metrics = getMetrics();
      expect(metrics[0].metadata?.extra).toBe('data');
    });
  });

  describe('useWebVitals', () => {
    it('should track Web Vitals from observers', async () => {
      let vitalsRef: any;
      const TestComponent = defineComponent({
        setup() {
          const { vitals } = useWebVitals();
          vitalsRef = vitals;
          return {};
        },
        template: '<div></div>'
      });
      
      mount(TestComponent);
      await nextTick();
      
      expect(globalThis.PerformanceObserver).toHaveBeenCalled();
      
      // Trigger LCP
      const lcpEntry = { name: 'LCP', startTime: 2000, entryType: 'largest-contentful-paint' };
      (globalThis as any).triggerPerformanceObserver('largest-contentful-paint', [lcpEntry]);
      expect(vitalsRef.value.LCP).toBe(2000);
      
      // Trigger FID
      const fidEntry = { name: 'FID', startTime: 1000, processingStart: 1150, entryType: 'first-input' };
      (globalThis as any).triggerPerformanceObserver('first-input', [fidEntry]);
      expect(vitalsRef.value.FID).toBe(150);
      
      // Trigger CLS
      const clsEntry = { name: 'CLS', value: 0.05, hadRecentInput: false, entryType: 'layout-shift' };
      (globalThis as any).triggerPerformanceObserver('layout-shift', [clsEntry]);
      expect(vitalsRef.value.CLS).toBe(0.05);

      const metrics = getMetrics();
      expect(metrics.some(m => m.name === 'LCP')).toBe(true);
      expect(metrics.some(m => m.name === 'FID')).toBe(true);
      expect(metrics.some(m => m.name === 'CLS')).toBe(true);
    });
    
    it('should handle missing globalThis gracefully', async () => {
      vi.stubGlobal('import.meta', { env: { DEV: true, PROD: false } });
      
      const { useWebVitals } = await import('@/composables/usePerformance');
      
      const TestComponent = defineComponent({
        setup() {
          useWebVitals();
          return {};
        },
        template: '<div></div>',
      });

      expect(() => mount(TestComponent)).not.toThrow();
    });
  });

  describe('useRenderTime', () => {
    it('should measure component render time', async () => {
      let time = 1000;
      (globalThis.performance.now as any).mockImplementation(() => {
        time += 200;
        return time;
      });
        
      const TestComponent = defineComponent({
        setup() {
          const { startMeasure } = useRenderTime('TestComp');
          startMeasure();
          return {};
        },
        template: '<div></div>',
      });
      
      const wrapper = mount(TestComponent);
      
      // Wait for onMounted (sync in mounting normally, but good to be safe)
      await wrapper.vm.$nextTick(); 
      
      const metrics = getMetrics();
      // It only logs if > 100ms. 200 > 100.
      expect(metrics.length).toBeGreaterThan(0);
      expect(metrics[0].name).toBe('component_render');
      expect(metrics[0].metadata?.component).toBe('TestComp');
      expect(metrics[0].value).toBeGreaterThanOrEqual(200);
    });

    it('should not log fast renders under 100ms', async () => {
      let time = 1000;
      (globalThis.performance.now as any).mockImplementation(() => {
        time += 50;
        return time;
      });

      const TestComponent = defineComponent({
        setup() {
          const { startMeasure } = useRenderTime('FastComp');
          startMeasure();
          return {};
        },
        template: '<div></div>',
      });

      mount(TestComponent);
      
      const metrics = getMetrics();
      expect(metrics.length).toBe(0);
    });
  });

  describe('measureSync', () => {
    it('should measure sync function', () => {
      let time = 1000;
      (globalThis.performance.now as any).mockImplementation(() => {
        time += 50;
        return time;
      });

      const result = measureSync('sync-test', () => 'success');
      expect(result).toBe('success');

      const metrics = getMetrics();
      expect(metrics).toHaveLength(1);
      expect(metrics[0].name).toBe('sync-test');
      expect(metrics[0].value).toBeGreaterThanOrEqual(50);
    });

    it('should pass metadata to logged metric', () => {
      (globalThis.performance.now as any)
        .mockReturnValueOnce(1000)
        .mockReturnValueOnce(1050);

      measureSync('test', () => {}, { context: 'unit-test' });

      const metrics = getMetrics();
      expect(metrics[0].metadata?.context).toBe('unit-test');
    });
  });

  describe('useApiTiming', () => {
    it('should track api calls', async () => {
      const { trackApiCall } = useApiTiming();
      
      let time = 1000;
      (globalThis.performance.now as any).mockImplementation(() => {
        time += 300;
        return time;
      });

      const result = await trackApiCall('/api/test', 'GET', async () => 'data');
      
      expect(result).toBe('data');
      const metrics = getMetrics();
      expect(metrics).toHaveLength(1);
      expect(metrics[0].name).toBe('api_GET_/api/test');
      expect(metrics[0].metadata?.endpoint).toBe('/api/test');
    });

    it('should track api calls with errors', async () => {
      const { trackApiCall } = useApiTiming();
      
      (globalThis.performance.now as any)
        .mockReturnValueOnce(1000)
        .mockReturnValueOnce(500);

      await expect(
        trackApiCall('/api/error', 'POST', async () => {
          throw new Error('Network error');
        })
      ).rejects.toThrow('Network error');

      const metrics = getMetrics();
      expect(metrics[0].metadata?.success).toBe(false);
    });
  });

});

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { useUploadCat } from '@/composables/useUploadCat';
import * as api from '@/utils/api';
import * as imageUtils from '@/utils/imageUtils';
// env import removed

// Mock dependencies
vi.mock('@/utils/api', () => ({
  uploadFile: vi.fn(),
  api: {
    get: vi.fn(),
    post: vi.fn(),
  },
  ApiError: class ApiError extends Error {
    type: string;
    constructor(type: string, message: string) {
      super(message);
      this.type = type;
    }
  },
  ApiErrorTypes: {
    NETWORK_ERROR: 'NETWORK_ERROR',
    AUTHENTICATION_ERROR: 'AUTHENTICATION_ERROR',
    VALIDATION_ERROR: 'VALIDATION_ERROR',
    SERVER_ERROR: 'SERVER_ERROR',
  },
}));

vi.mock('@/utils/imageUtils', () => ({
  optimizeImage: vi.fn(),
  validateImageFile: vi.fn(),
  getImageDimensions: vi.fn(),
}));

vi.mock('@/utils/env', () => ({
  isDev: vi.fn().mockReturnValue(false), // Default to false to avoid console logs in tests
  getEnvVar: vi.fn().mockReturnValue('1080'),
}));

describe('useUploadCat', () => {
  let mockFile: File;
  let mockLocationData: any;

  beforeEach(() => {
    vi.clearAllMocks();
    mockFile = new File(['test'], 'test.jpg', { type: 'image/jpeg' });
    mockLocationData = {
      lat: '123.456',
      lng: '78.90',
      location_name: 'Test Spot',
    };
  });

  it('should initialize with default state', () => {
    const { isUploading, error, uploadProgress } = useUploadCat();
    expect(isUploading.value).toBe(false);
    expect(error.value).toBe(null);
    expect(uploadProgress.value).toBe(0);
  });

  it('should fail validation if file is invalid', async () => {
    vi.spyOn(imageUtils, 'validateImageFile').mockReturnValue({ valid: false, error: 'Invalid file' });
    
    const { uploadCatPhoto, error } = useUploadCat();
    const result = await uploadCatPhoto(mockFile, mockLocationData);

    expect(result).toBeNull();
    expect(error.value).toBe('Invalid file');
    expect(imageUtils.validateImageFile).toHaveBeenCalledWith(mockFile);
  });

  it('should successfully upload a valid file', async () => {
    vi.spyOn(imageUtils, 'validateImageFile').mockReturnValue({ valid: true });
    vi.spyOn(imageUtils, 'getImageDimensions').mockResolvedValue({ width: 100, height: 100 });
    vi.spyOn(imageUtils, 'optimizeImage').mockResolvedValue(mockFile);
    vi.spyOn(api, 'uploadFile').mockResolvedValue({ id: '123', url: 'http://test.com/img.jpg' });

    const { uploadCatPhoto, isUploading, error } = useUploadCat();
    
    // Check loading state during upload
    const uploadPromise = uploadCatPhoto(mockFile, mockLocationData);
    expect(isUploading.value).toBe(true);
    
    const result = await uploadPromise;

    expect(isUploading.value).toBe(false);
    expect(error.value).toBeNull();
    expect(result).toEqual({ id: '123', url: 'http://test.com/img.jpg' });
    expect(api.uploadFile).toHaveBeenCalled();
  });

  it('should handle different API error types', async () => {
    vi.spyOn(imageUtils, 'validateImageFile').mockReturnValue({ valid: true });
    vi.spyOn(imageUtils, 'getImageDimensions').mockResolvedValue({ width: 100, height: 100 });
    vi.spyOn(imageUtils, 'optimizeImage').mockResolvedValue(mockFile);
    
    const { uploadCatPhoto, error } = useUploadCat();

    // Network Error
    let mockError = new api.ApiError(api.ApiErrorTypes.NETWORK_ERROR, 'Offline');
    vi.spyOn(api, 'uploadFile').mockRejectedValue(mockError);
    await uploadCatPhoto(mockFile, mockLocationData);
    expect(error.value).toContain('internet connection');

    // Auth Error
    mockError = new api.ApiError(api.ApiErrorTypes.AUTHENTICATION_ERROR, 'Expired');
    vi.spyOn(api, 'uploadFile').mockRejectedValue(mockError);
    await uploadCatPhoto(mockFile, mockLocationData);
    expect(error.value).toContain('log in again');

    // Validation Error
    mockError = new api.ApiError(api.ApiErrorTypes.VALIDATION_ERROR, 'Invalid data');
    vi.spyOn(api, 'uploadFile').mockRejectedValue(mockError);
    await uploadCatPhoto(mockFile, mockLocationData);
    expect(error.value).toBe('Invalid data');

    // Default Error
    // @ts-ignore
    mockError = new api.ApiError('UNKNOWN', 'Something weird');
    vi.spyOn(api, 'uploadFile').mockRejectedValue(mockError);
    await uploadCatPhoto(mockFile, mockLocationData);
    expect(error.value).toBe('Something weird');

    // Generic Error (not ApiError)
    vi.spyOn(api, 'uploadFile').mockRejectedValue(new Error('Generic fail'));
    await uploadCatPhoto(mockFile, mockLocationData);
    expect(error.value).toBe('Generic fail');
  });

  it('should update progress', async () => {
    vi.spyOn(imageUtils, 'validateImageFile').mockReturnValue({ valid: true });
    vi.spyOn(imageUtils, 'getImageDimensions').mockResolvedValue({ width: 100, height: 100 });
    vi.spyOn(imageUtils, 'optimizeImage').mockResolvedValue(mockFile);
    
    vi.spyOn(api, 'uploadFile').mockImplementation(async (_url, _file, _data, onProgress) => {
      if (onProgress) {
        onProgress({ 
          lengthComputable: true, 
          loaded: 50, 
          total: 100, 
          bytes: 50,
          rate: 100,
          estimated: 0,
          upload: true 
        } as any);
      }
      return { success: true };
    });

    const { uploadCatPhoto, uploadProgress } = useUploadCat();
    await uploadCatPhoto(mockFile, mockLocationData);

    expect(uploadProgress.value).toBe(50);
  });

  it('should reset state', () => {
    const { isUploading, error, uploadProgress, resetState } = useUploadCat();
    
    isUploading.value = true;
    error.value = 'Some error';
    uploadProgress.value = 50;

    resetState();

    expect(isUploading.value).toBe(false);
    expect(error.value).toBe(null);
    expect(uploadProgress.value).toBe(0);
  });

  it('should fetch quota status', async () => {
    const mockQuota = { used: 1, limit: 5, remaining: 4, is_pro: false };
    // @ts-ignore
    vi.spyOn(api.api, 'get').mockResolvedValue(mockQuota);

    const { getUploadQuota } = useUploadCat();
    const result = await getUploadQuota();

    expect(api.api.get).toHaveBeenCalledWith('/api/v1/upload/quota');
    expect(result).toEqual(mockQuota);
  });

  it('should handle quota fetch errors', async () => {
    // @ts-ignore
    vi.spyOn(api.api, 'get').mockRejectedValue(new Error('Quota fail'));
    const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => {});

    const { getUploadQuota } = useUploadCat();
    const result = await getUploadQuota();

    expect(result).toBeNull();
    expect(consoleSpy).toHaveBeenCalled();
    consoleSpy.mockRestore();
  });
});

