        { tag: 'cute', count: 10 },
        { tag: 'sleepy', count: 5 },
      ];
      store.setPopularTags(tags);
      expect(store.popularTags).toEqual(tags);
    });
  });

  // ========== Pagination ==========
  describe('Pagination', () => {
    it('should go to next page when has more', () => {
      const store = useCatsStore();
      store.setLocations(
        [],
        {
          total: 100,
          limit: 20,
          offset: 0,
          has_more: true,
          page: 1,
          total_pages: 5,
        }
      );

      store.nextPage();
      expect(store.currentPage).toBe(2);
      expect(store.pagination.offset).toBe(20);
    });

    it('should not go to next page when no more', () => {
      const store = useCatsStore();
      store.setLocations(
        [],
        {
          total: 20,
          limit: 20,
          offset: 0,
          has_more: false,
          page: 1,
          total_pages: 1,
        }
      );

      store.nextPage();
      expect(store.currentPage).toBe(1);
    });

    it('should go to previous page', () => {
      const store = useCatsStore();
      store.setLocations(
        [],
        {
          total: 100,
          limit: 20,
          offset: 20,
          has_more: true,
          page: 2,
          total_pages: 5,
        }
      );

      store.prevPage();
      expect(store.currentPage).toBe(1);
      expect(store.pagination.offset).toBe(0);
    });

    it('should not go below page 1', () => {
      const store = useCatsStore();
      store.prevPage();
      expect(store.currentPage).toBe(1);
    });

    it('should go to specific page', () => {
      const store = useCatsStore();
      store.setLocations(
        [],
        {
          total: 100,
          limit: 20,
          offset: 0,
          has_more: true,
          page: 1,
          total_pages: 5,
        }
      );

      store.goToPage(3);
      expect(store.currentPage).toBe(3);
      expect(store.pagination.offset).toBe(40);
    });

    it('should reset pagination', () => {
      const store = useCatsStore();
      store.setLocations(
        [],
        {
          total: 100,
          limit: 20,
          offset: 40,
          has_more: true,
          page: 3,
          total_pages: 5,
        }
      );

      store.resetPagination();
      expect(store.currentPage).toBe(1);
      expect(store.pagination.offset).toBe(0);
    });
  });

  // ========== Loading & Error States ==========
  describe('Loading & Error States', () => {
    it('should set loading state', () => {
      const store = useCatsStore();
      store.setLoading(true);
      expect(store.isLoading).toBe(true);
      
      store.setLoading(false);
      expect(store.isLoading).toBe(false);
    });

    it('should set error state', () => {
      const store = useCatsStore();
      store.setError('Network error');
      expect(store.error).toBe('Network error');

      store.setError(null);
      expect(store.error).toBeNull();
    });
  });

  // ========== Persistence & Side Effects ==========
  describe('Persistence & Side Effects', () => {
    it('should clear previous timer on rapid updates (debounce clearing)', async () => {
      const store = useCatsStore();
      
      // First update
      store.locations = [{ id: '1' } as any];
      
      // Wait a tiny bit but less than 2000ms
      await vi.advanceTimersByTimeAsync(500);
      
      // Second update
      store.locations = [{ id: '2' } as any];
      
      // Now wait for the full debounce
      await vi.advanceTimersByTimeAsync(2000);
      
      // setItem should only be called once with the latest data
      // (The first timer was cleared by line 81)
      expect(localStorage.setItem).toHaveBeenCalledTimes(1);
      expect(localStorage.setItem).toHaveBeenCalledWith(
        'cats_store_cache', 
        expect.stringContaining('"id":"2"')
      );
    });

    it('should debounce localStorage writes', async () => {
      const store = useCatsStore();
      
      // Update locations and wait for watch microtask
      store.locations = [{ id: '1' } as any];
      
      // watch callback is scheduled. Advance timers to trigger the debounced function.
      await vi.advanceTimersByTimeAsync(2000);
      
      expect(localStorage.setItem).toHaveBeenCalledWith(
        'cats_store_cache', 
        expect.stringContaining('"id":"1"')
      );
    });

    it('should limit cache size to 100 on write', async () => {
      const store = useCatsStore();
      const largeList = Array.from({ length: 150 }, (_, i) => ({ id: i.toString() } as any));
      
      store.locations = largeList;
      await vi.advanceTimersByTimeAsync(2000);
      
      const setItemCalls = (localStorage.setItem as any).mock.calls;
      expect(setItemCalls.length).toBeGreaterThan(0);
      const saved = JSON.parse(setItemCalls[0][1]);
      expect(saved.locations).toHaveLength(100);
    });

    it('should handle localStorage write errors gracefully', async () => {
      const store = useCatsStore();
      vi.mocked(localStorage.setItem).mockImplementation(() => { 
        throw new Error('Quota exceeded'); 
      });
      
      store.locations = [{ id: 'error' } as any];
      await vi.advanceTimersByTimeAsync(2000);
      // Should not throw (handled in store)
    });
  });

  // ========== Additional Getters ==========
  describe('Additional Getters', () => {
    it('popularTagsComputed should calculate correctly and limit to 10', () => {
      const store = useCatsStore();
      const largeLocationList = Array.from({ length: 15 }, (_, i) => ({
        id: i.toString(),
        tags: [`tag${i}`],
        description: ''
      } as any));
      
      store.setLocations(largeLocationList);

      const popular = store.popularTagsComputed;
      expect(popular).toHaveLength(10);
      expect(popular[0].count).toBe(1);
    });

    it('popularTagsComputed should handle duplicate tags in description vs array', () => {
      const store = useCatsStore();
      store.setLocations([
        { id: '1', tags: ['cute'], description: '#cute cat' } as any,
      ]);
      // It uses locations.tags IF it exists, otherwise extractTags.
      // Line 156: const tags = location.tags || extractTags(location.description);
      const popular = store.popularTagsComputed;
      expect(popular).toHaveLength(1);
      expect(popular[0].count).toBe(1);
    });

    it('allTags should sort alphabetically and handle duplicates', () => {
      const store = useCatsStore();
      store.setLocations([
        { id: '1', tags: ['zebra', 'apple'], description: '#apple #banana' } as any,
      ]);
      // allTags uses BOTH tags and description tags via extractTags
      expect(store.allTags).toEqual(['apple', 'banana', 'zebra']);
    });
  });

  // ========== Edge Cases ==========
  describe('Edge Cases', () => {
    it('clearGallerySearch should clear gallerySearchQuery', () => {
      const store = useCatsStore();
      store.setGallerySearchQuery('test');
      store.clearGallerySearch();
      expect(store.gallerySearchQuery).toBe('');
    });

    it('clearFilters should reset search and tags', () => {
      const store = useCatsStore();
      store.setSearchQuery('test');
      store.toggleTag('cute');
      store.clearFilters();
      expect(store.searchQuery).toBe('');
      expect(store.selectedTags).toEqual([]);
    });

    it('goToPage should validate page range', () => {
      const store = useCatsStore();
      store.setLocations([], { total: 40, limit: 20, offset: 0, has_more: true, page: 1, total_pages: 2 });
      
      store.goToPage(3);
      expect(store.currentPage).toBe(1);
      
      store.goToPage(0);
      expect(store.currentPage).toBe(1);
      
      store.goToPage(2);
      expect(store.currentPage).toBe(2);
      expect(store.pagination.offset).toBe(20);
    });
  });


});

